## Usage Examples

### Example 1: Basic Subscription and Consumption

```java
Properties props = new Properties();
props.setProperty("bootstrap.servers", "localhost:9092");
props.setProperty("group.id", "test-group");
props.setProperty("enable.auto.commit", "true");
props.setProperty("auto.commit.interval.ms", "1000");
props.setProperty("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
props.setProperty("value.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");

KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
consumer.subscribe(Arrays.asList("topic1", "topic2"));

try {
    while (true) {
        ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
        for (ConsumerRecord<String, String> record : records) {
            System.out.printf("topic=%s, partition=%d, offset=%d, key=%s, value=%s%n",
                record.topic(), record.partition(), record.offset(),
                record.key(), record.value());
        }
    }
} finally {
    consumer.close();
}
```

### Example 2: Rebalance Listener with Manual Commits

```java
Properties props = new Properties();
props.setProperty("bootstrap.servers", "localhost:9092");
props.setProperty("group.id", "test-group");
props.setProperty("enable.auto.commit", "false");
props.setProperty("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
props.setProperty("value.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");

KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);

ConsumerRebalanceListener listener = new ConsumerRebalanceListener() {
    @Override
    public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
        System.out.println("Committing offsets for revoked partitions: " + partitions);
        consumer.commitSync();
    }

    @Override
    public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
        System.out.println("New partitions assigned: " + partitions);
    }
};

consumer.subscribe(Arrays.asList("topic"), listener);

try {
    while (true) {
        ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
        for (ConsumerRecord<String, String> record : records) {
            System.out.printf("offset=%d, key=%s, value=%s%n",
                record.offset(), record.key(), record.value());
        }

        // Commit offsets after processing batch
        consumer.commitSync();
    }
} finally {
    consumer.close();
}
```

### Example 3: Seek to Timestamp

```java
Properties props = new Properties();
props.setProperty("bootstrap.servers", "localhost:9092");
props.setProperty("group.id", "test-group");
props.setProperty("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
props.setProperty("value.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");

KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
consumer.assign(Arrays.asList(
    new TopicPartition("topic", 0),
    new TopicPartition("topic", 1)
));

// Seek to messages from 1 hour ago
long oneHourAgo = System.currentTimeMillis() - (60 * 60 * 1000);
Map<TopicPartition, Long> timestamps = new HashMap<>();
for (TopicPartition partition : consumer.assignment()) {
    timestamps.put(partition, oneHourAgo);
}

Map<TopicPartition, OffsetAndTimestamp> offsets = consumer.offsetsForTimes(timestamps);
for (Map.Entry<TopicPartition, OffsetAndTimestamp> entry : offsets.entrySet()) {
    if (entry.getValue() != null) {
        consumer.seek(entry.getKey(), entry.getValue().offset());
    }
}

try {
    while (true) {
        ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
        for (ConsumerRecord<String, String> record : records) {
            System.out.printf("timestamp=%d, offset=%d, value=%s%n",
                record.timestamp(), record.offset(), record.value());
        }
    }
} finally {
    consumer.close();
}
```

### Example 4: Multi-Threaded Processing with Pause/Resume

```java
BlockingQueue<ConsumerRecord<String, String>> queue = new LinkedBlockingQueue<>(1000);
boolean shutdown = false;

// Consumer thread
Thread consumerThread = new Thread(() -> {
    Properties props = new Properties();
    props.setProperty("bootstrap.servers", "localhost:9092");
    props.setProperty("group.id", "test-group");
    props.setProperty("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
    props.setProperty("value.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");

    KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
    consumer.subscribe(Arrays.asList("topic"));

    try {
        while (!shutdown) {
            ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
            for (ConsumerRecord<String, String> record : records) {
                queue.put(record);

                // Pause if queue is getting full
                if (queue.size() > 800) {
                    consumer.pause(consumer.assignment());
                } else if (queue.size() < 200) {
                    consumer.resume(consumer.assignment());
                }
            }
        }
    } finally {
        consumer.close();
    }
});

// Worker thread
Thread workerThread = new Thread(() -> {
    while (!shutdown) {
        try {
            ConsumerRecord<String, String> record = queue.poll(1, TimeUnit.SECONDS);
            if (record != null) {
                processRecord(record);
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
});

consumerThread.start();
workerThread.start();

// Later, shutdown
shutdown = true;
consumerThread.join();
workerThread.join();
```

